"use client";
import { useMemo, useState } from "react";
import Link from "next/link";
import {
  Filter,
  Users,
  Target,
  ArrowRight,
  ArrowLeft,
  Plus,
  Check,
  Quote,
  Sparkles,
  ExternalLink,
  RefreshCw,
} from "lucide-react";
import { useFetch } from "@/components/useFetch";
import { TEACHER_QUOTES, POSITIONING_TEMPLATE } from "@/lib/frameworks";
import clsx from "clsx";

type Segment = {
  id: string;
  name: string;
  description: string;
  rules: { field: string; op: string; value: string }[];
  contact_count: number;
  color: string;
};

type Persona = {
  id: string;
  name: string;
  role: string;
  avatar: string;
  demographics: Record<string, unknown>;
  goals: string[];
  pain_points: string[];
  channels: string[];
  messaging: string;
  tier: "primary" | "secondary" | "negative";
};

type Positioning = {
  id: string;
  target: string;
  frame_of_reference: string;
  points_of_difference: string;
  reasons_to_believe: string;
  brand_character?: string;
  one_word_positioning?: string;
  notes?: string;
  updated_at: number;
};

const STEPS = [
  { id: "segment", label: "Segment", icon: Filter, sub: "Who could buy" },
  { id: "target", label: "Target", icon: Users, sub: "Who you choose" },
  { id: "position", label: "Position", icon: Target, sub: "What you promise" },
] as const;

type StepId = (typeof STEPS)[number]["id"];

export default function StpWorkbench() {
  const segs = useFetch<Segment[]>("/api/segments");
  const pers = useFetch<Persona[]>("/api/personas");
  const pos = useFetch<Positioning[]>("/api/positioning");

  const [step, setStep] = useState<StepId>("segment");
  const [segId, setSegId] = useState<string | null>(null);
  const [perId, setPerId] = useState<string | null>(null);
  const [posId, setPosId] = useState<string | null>(null);

  const segment = (segs.data || []).find((s) => s.id === segId) || null;
  const persona = (pers.data || []).find((p) => p.id === perId) || null;
  const positioning = (pos.data || []).find((p) => p.id === posId) || null;

  const stepIndex = STEPS.findIndex((s) => s.id === step);

  const oneLiner = useMemo(() => {
    if (!positioning) return "";
    return POSITIONING_TEMPLATE.replace("[TARGET]", positioning.target || "—")
      .replace("[NEED/OPPORTUNITY]", "have this problem")
      .replace("[BRAND]", "we")
      .replace("[CATEGORY/FR-OF-REFERENCE]", positioning.frame_of_reference || "—")
      .replace("[PROMISE/POINTS-OF-DIFFERENCE]", positioning.points_of_difference || "—")
      .replace("[REASONS-TO-BELIEVE]", positioning.reasons_to_believe || "—");
  }, [positioning]);

  const q = TEACHER_QUOTES.kotler;

  function go(id: StepId) {
    setStep(id);
  }
  function next() {
    const i = STEPS.findIndex((s) => s.id === step);
    if (i < STEPS.length - 1) setStep(STEPS[i + 1].id);
  }
  function back() {
    const i = STEPS.findIndex((s) => s.id === step);
    if (i > 0) setStep(STEPS[i - 1].id);
  }

  const complete = !!segment && !!persona && !!positioning;

  return (
    <div className="space-y-5">
      <header className="flex items-start justify-between gap-4">
        <div>
          <div className="flex items-center gap-2">
            <span className="text-xs font-bold uppercase tracking-wider muted">Strategy</span>
            <span className="text-xs muted">/</span>
            <span className="text-xs font-bold uppercase tracking-wider text-[var(--accent)]">
              STP Protocol
            </span>
          </div>
          <h1 className="text-xl font-bold mt-1">Segment → Target → Position</h1>
          <p className="text-sm muted mt-1 max-w-2xl">
            Kotler's STP is the spine of every campaign. Segment the market, target the few who
            matter, then occupy one position in their mind. Chain the three steps here, then push
            the result into every other workbench.
          </p>
        </div>
        <div className="flex gap-2">
          <button
            onClick={() => {
              segs.reload();
              pers.reload();
              pos.reload();
            }}
            className="btn btn-ghost text-xs"
            title="Reload"
          >
            <RefreshCw className="w-3.5 h-3.5" />
          </button>
        </div>
      </header>

      <div
        className="card card-pad card-lift flex items-start gap-3"
        style={{
          background: "linear-gradient(135deg, rgba(124,58,237,0.05), rgba(236,72,153,0.05))",
        }}
      >
        <Quote className="w-5 h-5 text-accent flex-shrink-0 mt-0.5" />
        <div>
          <div className="font-medium text-sm">“{q.quote}”</div>
          <div className="text-xs muted mt-1">— {q.who}</div>
        </div>
      </div>

      {/* Stepper */}
      <div className="card card-pad">
        <div className="flex items-center gap-2 flex-wrap">
          {STEPS.map((s, i) => {
            const Icon = s.icon;
            const active = step === s.id;
            const done =
              (s.id === "segment" && !!segment) ||
              (s.id === "target" && !!persona) ||
              (s.id === "position" && !!positioning);
            return (
              <div key={s.id} className="flex items-center gap-2">
                <button
                  onClick={() => go(s.id)}
                  className={clsx(
                    "flex items-center gap-2 px-3 py-2 rounded-lg text-sm transition-colors border",
                    active
                      ? "border-[var(--accent)] text-[var(--accent)] bg-[rgba(var(--theme-brand-rgb),0.06)]"
                      : done
                        ? "border-emerald-300 text-emerald-700 bg-emerald-50"
                        : "border-[rgb(var(--border))] muted hover:bg-[rgb(var(--hover))]",
                  )}
                >
                  <span
                    className={clsx(
                      "w-6 h-6 rounded-full grid place-items-center text-xs font-bold",
                      active
                        ? "bg-[var(--accent)] text-white"
                        : done
                          ? "bg-emerald-500 text-white"
                          : "bg-[rgb(var(--hover))] text-[rgb(var(--text-secondary))]",
                    )}
                  >
                    {done ? <Check className="w-3 h-3" /> : i + 1}
                  </span>
                  <Icon className="w-4 h-4" />
                  <span className="font-semibold">{s.label}</span>
                  <span className="text-xs muted hidden sm:inline">{s.sub}</span>
                </button>
                {i < STEPS.length - 1 && (
                  <ArrowRight className="w-4 h-4 muted flex-shrink-0" />
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Active step body */}
      {step === "segment" && (
        <SegmentStep
          loading={segs.loading}
          data={segs.data || []}
          selectedId={segId}
          onSelect={(id) => {
            setSegId(id);
            next();
          }}
        />
      )}
      {step === "target" && (
        <TargetStep
          loading={pers.loading}
          data={pers.data || []}
          selectedId={perId}
          segment={segment}
          onSelect={(id) => {
            setPerId(id);
            next();
          }}
        />
      )}
      {step === "position" && (
        <PositionStep
          loading={pos.loading}
          data={pos.data || []}
          selectedId={posId}
          persona={persona}
          onSelect={setPosId}
        />
      )}

      {/* Nav */}
      <div className="flex items-center justify-between">
        <button
          className="btn btn-ghost text-sm"
          onClick={back}
          disabled={stepIndex === 0}
        >
          <ArrowLeft className="w-4 h-4" /> Back
        </button>
        {stepIndex < STEPS.length - 1 ? (
          <button className="btn btn-primary text-sm" onClick={next}>
            Next <ArrowRight className="w-4 h-4" />
          </button>
        ) : (
          <button
            className="btn btn-primary text-sm"
            onClick={() => setStep("segment")}
          >
            <RefreshCw className="w-4 h-4" /> Restart chain
          </button>
        )}
      </div>

      {/* Chain summary */}
      {(segment || persona || positioning) && (
        <ChainSummary
          segment={segment}
          persona={persona}
          positioning={positioning}
          oneLiner={oneLiner}
          complete={complete}
          onEdit={(id) => go(id)}
        />
      )}
    </div>
  );
}

/* ───────────────────────── Step: Segment ───────────────────────── */
function SegmentStep({
  loading,
  data,
  selectedId,
  onSelect,
}: {
  loading: boolean;
  data: Segment[];
  selectedId: string | null;
  onSelect: (id: string) => void;
}) {
  return (
    <section className="space-y-3">
      <StepHeader
        n={1}
        icon={Filter}
        title="Segment the market"
        desc="Split the whole market into groups with shared traits. You're not picking yet — you're drawing the boundaries."
        createHref="/segments"
        createLabel="Create segment"
      />
      {loading ? (
        <Skeleton />
      ) : data.length === 0 ? (
        <StepEmpty
          icon={Filter}
          title="No segments yet"
          desc="Group contacts by status, source, score, or any combination. Each segment is a candidate slice for targeting."
          href="/segments"
          cta="Open Segments"
        />
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
          {data.map((s) => {
            const active = s.id === selectedId;
            return (
              <button
                key={s.id}
                onClick={() => onSelect(s.id)}
                className={clsx(
                  "card card-pad text-left transition-all hover:shadow-md",
                  active
                    ? "ring-2 ring-[var(--accent)] border-[var(--accent)]"
                    : "hover:border-[color-mix(in_srgb,var(--accent),white_40%)]",
                )}
              >
                <div className="flex items-center gap-2 mb-1">
                  <div className="w-3 h-3 rounded-full" style={{ background: s.color }} />
                  <div className="font-semibold">{s.name}</div>
                  {active && <Check className="w-4 h-4 text-[var(--accent)] ml-auto" />}
                </div>
                <div className="text-xs muted mb-2">{s.description || "No description"}</div>
                <div className="flex items-center gap-1 text-xs">
                  <Users className="w-3 h-3" />
                  <span className="font-semibold">{s.contact_count.toLocaleString()}</span>
                  <span className="muted">contacts</span>
                </div>
                {(s.rules || []).length > 0 && (
                  <div className="mt-2 text-xs muted font-mono bg-slate-100 dark:bg-zinc-800 px-2 py-1 rounded">
                    {s.rules.length} rule{s.rules.length > 1 ? "s" : ""}
                  </div>
                )}
              </button>
            );
          })}
        </div>
      )}
    </section>
  );
}

/* ───────────────────────── Step: Target ───────────────────────── */
function TargetStep({
  loading,
  data,
  selectedId,
  segment,
  onSelect,
}: {
  loading: boolean;
  data: Persona[];
  selectedId: string | null;
  segment: Segment | null;
  onSelect: (id: string) => void;
}) {
  const grouped = data.reduce((acc: Record<string, Persona[]>, p) => {
    (acc[p.tier] = acc[p.tier] || []).push(p);
    return acc;
  }, {});

  return (
    <section className="space-y-3">
      <StepHeader
        n={2}
        icon={Users}
        title="Target your slice"
        desc="Pick the segment(s) worth pursuing and name the human inside them. This is the targeting decision — resource discipline."
        createHref="/personas"
        createLabel="Create persona"
      />
      {segment && (
        <div className="card card-pad flex items-center gap-2 text-sm bg-[rgba(var(--theme-brand-rgb),0.04)]">
          <Filter className="w-4 h-4 text-[var(--accent)]" />
          <span className="muted">Chained from segment:</span>
          <span className="font-semibold">{segment.name}</span>
          <span className="text-xs muted">· {segment.contact_count.toLocaleString()} contacts</span>
        </div>
      )}
      {loading ? (
        <Skeleton />
      ) : data.length === 0 ? (
        <StepEmpty
          icon={Users}
          title="No personas yet"
          desc="Build ICPs so every campaign speaks to a real human, not a demographic. Primary, secondary, and anti-personas."
          href="/personas"
          cta="Open Personas"
        />
      ) : (
        <div className="space-y-4">
          {(["primary", "secondary", "negative"] as const).map((tier) => {
            const list = grouped[tier] || [];
            if (list.length === 0) return null;
            return (
              <div key={tier}>
                <div className="text-xs font-bold uppercase tracking-wider muted mb-2">
                  {tier === "primary" ? "Primary" : tier === "secondary" ? "Secondary" : "Negative / Anti"}
                  <span className="ml-1 muted">({list.length})</span>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                  {list.map((p) => {
                    const active = p.id === selectedId;
                    return (
                      <button
                        key={p.id}
                        onClick={() => onSelect(p.id)}
                        className={clsx(
                          "card card-pad text-left transition-all hover:shadow-md",
                          active
                            ? "ring-2 ring-[var(--accent)] border-[var(--accent)]"
                            : "hover:border-[color-mix(in_srgb,var(--accent),white_40%)]",
                        )}
                      >
                        <div className="flex items-center gap-2 mb-2">
                          <div className="w-10 h-10 rounded-xl bg-slate-100 dark:bg-zinc-800 grid place-items-center text-xl">
                            {p.avatar}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="font-semibold truncate">{p.name}</div>
                            <div className="text-xs muted truncate">{p.role}</div>
                          </div>
                          {active && <Check className="w-4 h-4 text-[var(--accent)]" />}
                        </div>
                        {p.goals?.length > 0 && (
                          <div className="text-xs text-emerald-700 dark:text-emerald-400 mb-1">
                            ▸ {p.goals[0]}
                          </div>
                        )}
                        {p.pain_points?.length > 0 && (
                          <div className="text-xs text-rose-700 dark:text-rose-400 mb-1">
                            ▸ {p.pain_points[0]}
                          </div>
                        )}
                        {p.channels?.length > 0 && (
                          <div className="flex flex-wrap gap-1 mt-1">
                            {p.channels.slice(0, 3).map((c) => (
                              <span key={c} className="chip bg-violet-50 text-violet-700 text-[10px]">
                                {c}
                              </span>
                            ))}
                          </div>
                        )}
                      </button>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </section>
  );
}

/* ───────────────────────── Step: Position ───────────────────────── */
function PositionStep({
  loading,
  data,
  selectedId,
  persona,
  onSelect,
}: {
  loading: boolean;
  data: Positioning[];
  selectedId: string | null;
  persona: Persona | null;
  onSelect: (id: string) => void;
}) {
  return (
    <section className="space-y-3">
      <StepHeader
        n={3}
        icon={Target}
        title="Position in their mind"
        desc="Now occupy one spot. Fill the Kotler boxes — target, frame of reference, points of difference, reasons to believe — into one sentence."
        createHref="/strategy/positioning"
        createLabel="New positioning"
      />
      {persona && (
        <div className="card card-pad flex items-center gap-2 text-sm bg-[rgba(var(--theme-brand-rgb),0.04)]">
          <Users className="w-4 h-4 text-[var(--accent)]" />
          <span className="muted">Targeting:</span>
          <span className="font-semibold">{persona.name}</span>
          <span className="text-xs muted">· {persona.role}</span>
        </div>
      )}
      {loading ? (
        <Skeleton />
      ) : data.length === 0 ? (
        <StepEmpty
          icon={Target}
          title="No positioning yet"
          desc="Walk through the four Kotler boxes. You'll end up with the one sentence that drives every other decision."
          href="/strategy/positioning"
          cta="Open Positioning"
        />
      ) : (
        <div className="space-y-3">
          {data.map((p, i) => {
            const active = p.id === selectedId;
            const liner = POSITIONING_TEMPLATE.replace("[TARGET]", p.target || "—")
              .replace("[NEED/OPPORTUNITY]", "have this problem")
              .replace("[BRAND]", "we")
              .replace("[CATEGORY/FR-OF-REFERENCE]", p.frame_of_reference || "—")
              .replace("[PROMISE/POINTS-OF-DIFFERENCE]", p.points_of_difference || "—")
              .replace("[REASONS-TO-BELIEVE]", p.reasons_to_believe || "—");
            return (
              <button
                key={p.id}
                onClick={() => onSelect(p.id)}
                className={clsx(
                  "card card-pad text-left transition-all hover:shadow-md w-full",
                  active
                    ? "ring-2 ring-[var(--accent)] border-[var(--accent)]"
                    : "hover:border-[color-mix(in_srgb,var(--accent),white_40%)]",
                )}
              >
                <div className="flex items-start justify-between gap-3">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-2">
                      <span className="text-xs font-bold uppercase tracking-wider muted">
                        {i === 0 ? "Current" : "v" + (data.length - i)}
                      </span>
                      {p.one_word_positioning && (
                        <span className="text-sm font-bold text-[var(--accent)]">
                          the {p.one_word_positioning}
                        </span>
                      )}
