+                          </div>
+                        )}
+                      </button>
+                    );
+                  })}
+                </div>
+              </div>
+            );
+          })}
+        </div>
+      )}
+    </section>
+  );
+}
+
+/* ───────────────────────── Step: Position ───────────────────────── */
+function PositionStep({
+  loading,
+  data,
+  selectedId,
+  persona,
+  onSelect,
+}: {
+  loading: boolean;
+  data: Positioning[];
+  selectedId: string | null;
+  persona: Persona | null;
+  onSelect: (id: string) => void;
+}) {
+  return (
+    <section className="space-y-3">
+      <StepHeader
+        n={3}
+        icon={Target}
+        title="Position in their mind"
+        desc="Now occupy one spot. Fill the Kotler boxes — target, frame of reference, points of difference, reasons to believe — into one sentence."
+        createHref="/strategy/positioning"
+        createLabel="New positioning"
+      />
+      {persona && (
+        <div className="card card-pad flex items-center gap-2 text-sm bg-[rgba(var(--theme-brand-rgb),0.04)]">
+          <Users className="w-4 h-4 text-[var(--accent)]" />
+          <span className="muted">Targeting:</span>
+          <span className="font-semibold">{persona.name}</span>
+          <span className="text-xs muted">· {persona.role}</span>
+        </div>
+      )}
+      {loading ? (
+        <Skeleton />
+      ) : data.length === 0 ? (
+        <StepEmpty
+          icon={Target}
+          title="No positioning yet"
+          desc="Walk through the four Kotler boxes. You'll end up with the one sentence that drives every other decision."
+          href="/strategy/positioning"
+          cta="Open Positioning"
+        />
+      ) : (
+        <div className="space-y-3">
+          {data.map((p, i) => {
+            const active = p.id === selectedId;
+            const liner = POSITIONING_TEMPLATE.replace("[TARGET]", p.target || "—")
+              .replace("[NEED/OPPORTUNITY]", "have this problem")
+              .replace("[BRAND]", "we")
+              .replace("[CATEGORY/FR-OF-REFERENCE]", p.frame_of_reference || "—")
+              .replace("[PROMISE/POINTS-OF-DIFFERENCE]", p.points_of_difference || "—")
+              .replace("[REASONS-TO-BELIEVE]", p.reasons_to_believe || "—");
+            return (
+              <button
+                key={p.id}
+                onClick={() => onSelect(p.id)}
+                className={clsx(
+                  "card card-pad text-left transition-all hover:shadow-md w-full",
+                  active
+                    ? "ring-2 ring-[var(--accent)] border-[var(--accent)]"
+                    : "hover:border-[color-mix(in_srgb,var(--accent),white_40%)]",
+                )}
+              >
+                <div className="flex items-start justify-between gap-3">
+                  <div className="flex-1 min-w-0">
+                    <div className="flex items-center gap-2 mb-2">
+                      <span className="text-xs font-bold uppercase tracking-wider muted">
+                        {i === 0 ? "Current" : "v" + (data.length - i)}
+                      </span>
+                      {p.one_word_positioning && (
+                        <span className="text-sm font-bold text-[var(--accent)]">
+                          the {p.one_word_positioning}
+                        </span>
+                      )}
+                      {active && <Check className="w-4 h-4 text-[var(--accent)] ml-auto" />}
+                    </div>
+                    <blockquote
+                      className="text-sm italic border-l-4 pl-3"
+                      style={{ borderColor: "var(--accent)" }}
+                    >
+                      {liner}
+                    </blockquote>
+                    <div className="grid grid-cols-2 gap-2 mt-3 text-xs">
+                      <Field label="Target" body={p.target} />
+                      <Field label="Frame" body={p.frame_of_reference} />
+                      <Field label="Difference" body={p.points_of_difference} />
+                      <Field label="Proof" body={p.reasons_to_believe} />
+                    </div>
+                  </div>
+                </div>
+              </button>
+            );
+          })}
+        </div>
+      )}
+    </section>
+  );
+}
+
+/* ───────────────────────── Chain summary ───────────────────────── */
+function ChainSummary({
+  segment,
+  persona,
+  positioning,
+  oneLiner,
+  complete,
+  onEdit,
+}: {
+  segment: Segment | null;
+  persona: Persona | null;
+  positioning: Positioning | null;
+  oneLiner: string;
+  complete: boolean;
+  onEdit: (id: StepId) => void;
+}) {
+  return (
+    <div
+      className="card card-pad card-lift"
+      style={{
+        background: complete
+          ? "linear-gradient(135deg, rgba(16,163,74,0.06), rgba(124,58,237,0.06))"
+          : "linear-gradient(135deg, rgba(var(--theme-brand-rgb),0.04), rgba(236,72,153,0.04))",
+      }}
+    >
+      <div className="flex items-center gap-2 mb-3">
+        <Sparkles className="w-5 h-5 text-[var(--accent)]" />
+        <h2 className="font-bold">STP chain</h2>
+        {complete && (
+          <span className="chip bg-emerald-100 text-emerald-700 text-[10px] font-bold uppercase">
+            Complete
+          </span>
+        )}
+      </div>
+
+      <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
+        <ChainNode
+          n={1}
+          icon={Filter}
+          label="Segment"
+          title={segment?.name}
+          sub={segment ? `${segment.contact_count.toLocaleString()} contacts` : undefined}
+          href="/segments"
+          onClick={() => onEdit("segment")}
+        />
+        <Arrow />
+        <ChainNode
+          n={2}
+          icon={Users}
+          label="Target"
+          title={persona?.name}
+          sub={persona?.role}
+          href="/personas"
+          onClick={() => onEdit("target")}
+        />
+        <Arrow />
+        <ChainNode
+          n={3}
+          icon={Target}
+          label="Position"
+          title={positioning?.one_word_positioning ? `the ${positioning.one_word_positioning}` : undefined}
+          sub={positioning?.frame_of_reference}
+          href="/strategy/positioning"
+          onClick={() => onEdit("position")}
+        />
+      </div>
+
+      {oneLiner && (
+        <div className="mt-4 pt-4 border-t" style={{ borderColor: "rgb(var(--border))" }}>
+          <div className="text-xs uppercase tracking-wider muted mb-1">One-line positioning</div>
+          <blockquote
+            className="text-sm italic border-l-4 pl-3"
+            style={{ borderColor: "var(--accent)" }}
+          >
+            {oneLiner}
+          </blockquote>
+        </div>
+      )}
+
+      {!complete && (
+        <div className="text-xs muted mt-3">
+          Complete all three steps to lock the chain. Each node links to its full workbench for edits.
+        </div>
+      )}
+    </div>
+  );
+}
+
+function ChainNode({
+  n,
+  icon: Icon,
+  label,
+  title,
+  sub,
+  href,
+  onClick,
+}: {
+  n: number;
+  icon: React.ComponentType<{ className?: string }>;
+  label: string;
+  title?: string;
+  sub?: string;
+  href: string;
+  onClick: () => void;
+}) {
+  return (
+    <button
+      onClick={onClick}
+      className="card p-3 text-left hover:shadow-md transition-all group"
+    >
+      <div className="flex items-center gap-2 mb-1">
+        <span className="w-5 h-5 rounded-full grid place-items-center text-[10px] font-bold bg-[rgb(var(--hover))] text-[rgb(var(--text-secondary))]">
+          {n}
+        </span>
+        <Icon className="w-3.5 h-3.5 text-[var(--accent)]" />
+        <span className="text-xs font-bold uppercase tracking-wider muted">{label}</span>
+      </div>
+      {title ? (
+        <div className="font-semibold text-sm truncate">{title}</div>
+      ) : (
+        <div className="text-sm muted italic">Not selected</div>
+      )}
+      {sub && <div className="text-xs muted truncate">{sub}</div>}
+      <div className="text-[10px] muted mt-1 flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
+        <ExternalLink className="w-2.5 h-2.5" /> {href}
+      </div>
+    </button>
+  );
+}
+
+function Arrow() {
+  return (
+    <div className="hidden md:flex items-center justify-center">
+      <ArrowRight className="w-4 h-4 muted" />
+    </div>
+  );
+}
+
+/* ───────────────────────── Small parts ───────────────────────── */
+function StepHeader({
+  n,
+  icon: Icon,
+  title,
+  desc,
+  createHref,
+  createLabel,
+}: {
+  n: number;
+  icon: React.ComponentType<{ className?: string }>;
+  title: string;
+  desc: string;
+  createHref: string;
+  createLabel: string;
+}) {
+  return (
+    <div className="flex items-start justify-between gap-3">
+      <div className="flex items-start gap-3">
+        <div className="w-9 h-9 rounded-xl bg-[rgba(var(--theme-brand-rgb),0.08)] grid place-items-center text-[var(--accent)]">
+          <Icon className="w-5 h-5" />
+        </div>
+        <div>
+          <div className="text-xs font-bold uppercase tracking-wider muted">Step {n}</div>
+          <h2 className="font-bold">{title}</h2>
+          <p className="text-sm muted max-w-xl mt-0.5">{desc}</p>
+        </div>
+      </div>
+      <Link href={createHref} className="btn btn-ghost text-xs whitespace-nowrap">
+        <Plus className="w-3 h-3" /> {createLabel}
+      </Link>
+    </div>
+  );
+}
+
+function StepEmpty({
+  icon: Icon,
+  title,
+  desc,
+  href,
+  cta,
+}: {
+  icon: React.ComponentType<{ className?: string }>;
+  title: string;
+  desc: string;
+  href: string;
+  cta: string;
+}) {
+  return (
+    <div className="card card-pad text-center py-12">
+      <Icon className="w-10 h-10 text-accent mx-auto" />
+      <h3 className="font-semibold mt-3">{title}</h3>
+      <p className="text-sm muted max-w-md mx-auto mt-1">{desc}</p>
+      <Link href={href} className="btn btn-primary mt-4 inline-flex">
+        {cta} <ExternalLink className="w-3.5 h-3.5" />
+      </Link>
+    </div>
+  );
+}
+
+function Skeleton() {
+  return (
+    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
+      {[0, 1, 2].map((i) => (
+        <div key={i} className="card card-pad animate-pulse">
+          <div className="h-4 w-1/2 bg-[rgb(var(--hover))] rounded mb-2" />
+          <div className="h-3 w-3/4 bg-[rgb(var(--hover))] rounded mb-3" />
+          <div className="h-3 w-1/3 bg-[rgb(var(--hover))] rounded" />
+        </div>
+      ))}
+    </div>
+  );
+}
+
+function Field({ label, body }: { label: string; body?: string }) {
+  if (!body) return null;
+  return (
+    <div className="min-w-0">
+      <div className="text-[10px] uppercase tracking-wider muted">{label}</div>
+      <div className="truncate">{body}</div>
+    </div>
+  );
+}
