+                      )}
+                      {active && <Check className="w-4 h-4 text-[var(--accent)] ml-auto" />}
+                    </div>
+                    <blockquote
+                      className="text-sm italic border-l-4 pl-3"
+                      style={{ borderColor: "var(--accent)" }}
+                    >
+                      {liner}
+                    </blockquote>
+                    <div className="grid grid-cols-2 gap-2 mt-3 text-xs">
+                      <Field label="Target" body={p.target} />
+                      <Field label="Frame" body={p.frame_of_reference} />
+                      <Field label="Difference" body={p.points_of_difference} />
+                      <Field label="Proof" body={p.reasons_to_believe} />
+                    </div>
+                  </div>
+                </div>
+              </button>
+            );
+          })}
+        </div>
+      )}
+    </section>
+  );
+}
+
+/* ───────────────────────── Chain summary ───────────────────────── */
+function ChainSummary({
+  segment,
+  persona,
+  positioning,
+  oneLiner,
+  complete,
+  onEdit,
