      { id: "differentiation", label: "Is your position differentiated from competitors?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "proof", label: "Do you have proof points that back the position?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "messaging_consistency", label: "Is your messaging consistent across channels?", type: "slider", min: 0, max: 10, default: 5 },
    ],
    scoring: [
      { max: 40, label: "Not ready — go back to strategy", color: "#ef4444" },
      { max: 60, label: "Partial — fill the gaps first", color: "#f59e0b" },
      { max: 80, label: "Mostly ready — tighten the weak spots", color: "#0ea5e9" },
      { max: 100, label: "Ready — go execute", color: "#16a34a" },
    ],
    compute: (i) => {
      const keys = ["segment_clarity", "segment_size", "target_fit", "positioning_clarity", "differentiation", "proof", "messaging_consistency"];
      const sum = keys.reduce((s, k) => s + Number(i[k] || 0), 0);
      const score = Math.round((sum / (keys.length * 10)) * 100);
      return { score, maxScore: 100 };
    },
  },
},

