{
  id: "porter_generic",
  label: "Generic Strategies",
  author: "Porter",
  category: "Competitive",
  oneLine: "Cost leadership, differentiation, or focus. Pick one or get stuck in the middle.",
  steps: ["Choose cost, differentiation, or focus", "Align operations to it", "Refuse the middle"],
  when: "Setting long-term competitive direction.",
  tool: {
    type: "scorecard",
    title: "Porter Strategy Fit Scorecard",
    description: "Score yourself on all three generic strategies. The highest wins. If all are <6, you're stuck in the middle.",
    inputs: [
      { id: "cost", label: "Cost leadership — are you the lowest-cost operator?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "diff", label: "Differentiation — is your offering uniquely valued?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "focus", label: "Focus — do you serve a narrow segment exceptionally?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "operations", label: "Are your operations aligned to your top strategy?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "discipline", label: "Do you refuse opportunities outside your strategy?", type: "slider", min: 0, max: 10, default: 5 },
    ],
    scoring: [
      { max: 40, label: "Stuck in the middle — pick one strategy", color: "#ef4444" },
      { max: 60, label: "Drifting — align operations to your strongest", color: "#f59e0b" },
      { max: 80, label: "On track — tighten discipline", color: "#0ea5e9" },
      { max: 100, label: "Clear strategy — execute hard", color: "#16a34a" },
    ],
    compute: (i) => {
      const cost = Number(i.cost || 0);
      const diff = Number(i.diff || 0);
      const focus = Number(i.focus || 0);
      const ops = Number(i.operations || 0);
      const disc = Number(i.discipline || 0);
      const best = Math.max(cost, diff, focus);
      const score = Math.round(((best * 3 + ops + disc) / 50) * 100);
      const strategy = best === cost ? "Cost leadership" : best === diff ? "Differentiation" : "Focus";
      return { score: Math.min(100, score), maxScore: 100, verdict: `Strongest: ${strategy} (${best}/10)`, color: best >= 7 ? "#16a34a" : best >= 5 ? "#f59e0b" : "#ef4444" };
    },
  },
},

