{
  id: "ansoff",
  label: "Ansoff Matrix",
  author: "Ansoff",
  category: "Growth",
  oneLine: "Market penetration, development, product development, diversification.",
  steps: ["Existing product / existing market", "Existing / new market", "New / existing", "New / new"],
  when: "Choosing where growth comes from.",
  tool: {
    type: "decision_tree",
    title: "Ansoff Growth Path Selector",
    description: "Answer two questions to find which Ansoff growth strategy fits your situation.",
    inputs: [
      { id: "q1", label: "Are you selling to your existing market or a new one?", type: "radio", options: ["Existing market", "New market"] },
      { id: "q2", label: "Are you using your existing product or building a new one?", type: "radio", options: ["Existing product", "New product"] },
    ],
    compute: (i) => {
      const market = String(i.q1);
      const product = String(i.q2);
      if (market === "Existing market" && product === "Existing product") return { verdict: "Market Penetration — sell more of what you have to who you already serve. Lowest risk.", color: "#16a34a" };
      if (market === "Existing market" && product === "New product") return { verdict: "Product Development — build something new for your current customers. Medium risk.", color: "#0ea5e9" };
      if (market === "New market" && product === "Existing product") return { verdict: "Market Development — take your product to new geographies or segments. Medium risk.", color: "#f59e0b" };
      return { verdict: "Diversification — new product in a new market. Highest risk, highest reward.", color: "#ef4444" };
    },
  },
},

