input.newString:
{
  id: "bcg_matrix",
  label: "BCG Matrix",
  author: "BCG",
  category: "Growth",
  oneLine: "Stars, cash cows, question marks, dogs — allocate by growth & share.",
  steps: ["Plot growth vs share", "Starve dogs", "Milk cows", "Fund stars", "Decide on question marks"],
  when: "Portfolio allocation.",
  tool: {
    type: "calculator",
    title: "BCG Quadrant Calculator",
    description: "Enter market growth (%) and your relative market share (0–2, where 1 = parity with leader) for up to 4 products.",
    inputs: [
      { id: "p1_name", label: "Product 1 name", type: "text", default: "", placeholder: "Product A" },
      { id: "p1_growth", label: "Product 1 — market growth %", type: "number", default: 15 },
      { id: "p1_share", label: "Product 1 — relative market share", type: "number", default: 1.2 },
      { id: "p2_name", label: "Product 2 name", type: "text", default: "", placeholder: "Product B" },
      { id: "p2_growth", label: "Product 2 — market growth %", type: "number", default: 5 },
      { id: "p2_share", label: "Product 2 — relative market share", type: "number", default: 0.3 },
    ],
    compute: (i) => {
      function classify(growth: number, share: number) {
        const highGrowth = growth >= 10;
        const highShare = share >= 1;
        if (highGrowth && highShare) return { tag: "Star", tagColor: "#16a34a" };
        if (!highGrowth && highShare) return { tag: "Cash Cow", tagColor: "#f59e0b" };
        if (highGrowth && !highShare) return { tag: "Question Mark", tagColor: "#0ea5e9" };
        return { tag: "Dog", tagColor: "#94a3b8" };
      }
      const table = [
        { label: String(i.p1_name || "Product 1"), value: `${i.p1_growth}% growth, ${i.p1_share} share`, ...classify(Number(i.p1_growth), Number(i.p1_share)) },
        { label: String(i.p2_name || "Product 2"), value: `${i.p2_growth}% growth, ${i.p2_share} share`, ...classify(Number(i.p2_growth), Number(i.p2_share)) },
      ];
      return { table };
    },
  },
},

