    inputs: [
      { id: "salience", label: "Salience — do people recognize and recall your brand?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "performance", label: "Performance — does the product deliver on primary characteristics?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "imagery", label: "Imagery — do people associate the right profiles & imagery?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "judgments", label: "Judgments — do customers judge you positively (quality, credibility)?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "feelings", label: "Feelings — do you evoke positive emotional responses?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "resonance", label: "Resonance — do customers feel a deep, active relationship?", type: "slider", min: 0, max: 10, default: 5 },
    ],
    scoring: [
      { max: 40, label: "Weak brand equity — start with salience", color: "#ef4444" },
      { max: 60, label: "Developing — strengthen the lowest level", color: "#f59e0b" },
      { max: 80, label: "Strong — push toward resonance", color: "#0ea5e9" },
      { max: 100, label: "Excellent brand equity", color: "#16a34a" },
    ],
    compute: (i) => {
      const keys = ["salience", "performance", "imagery", "judgments", "feelings", "resonance"];
      const vals = keys.map((k) => Number(i[k] || 0));
      const sum = vals.reduce((a, b) => a + b, 0);
      const min = Math.min(...vals);
      const weakest = keys[vals.indexOf(min)];
      const score = Math.round((sum / (keys.length * 10)) * 100);
      return { score, maxScore: 100, verdict: `Weakest level: ${weakest} (${min}/10)`, color: min >= 7 ? "#16a34a" : min >= 4 ? "#f59e0b" : "#ef4444" };
    },
  },
},

{
  id: "awareness_levels",
  label: "5 Levels of Awareness",
  author: "Schwartz",
  category: "Customer",
  oneLine: "Unaware → problem → solution → product → most aware. Match copy to the level.",
  steps: ["Diagnose level", "Write copy for that level", "Ascend the ladder"],
  when: "Copy and funnel design.",
  tool: {
    type: "decision_tree",
    title: "Awareness Level Diagnostic",
    description: "Pick the description that best matches your audience. The output tells you which copy strategy to use.",
    inputs: [
      { id: "level", label: "Which best describes your audience right now?", type: "select", options: [
        "They don't even know they have the problem",
        "They feel the pain but don't know solutions exist",
        "They know solutions exist but not your product",
        "They know your product but haven't bought",
        "They want your product and are ready to buy",
      ] },
    ],
    compute: (i) => {
      const v = String(i.level);
      if (v.includes("don't even know")) return { verdict: "Unaware — tell a status-quo story first. Don't pitch the product yet.", color: "#94a3b8" };
      if (v.includes("feel the pain")) return { verdict: "Problem Aware — name and agitate the problem, then introduce the category.", color: "#0ea5e9" };
      if (v.includes("not your product")) return { verdict: "Solution Aware — show why your approach is better than alternatives.", color: "#f59e0b" };
      if (v.includes("haven't bought")) return { verdict: "Product Aware — mechanism, proof, comparison, objection-handling.", color: "#7c3aed" };
