{
  id: "rfm",
  label: "RFM Segmentation",
  author: "Hughes",
  category: "Customer",
  oneLine: "Recency, frequency, monetary — score and tier the base.",
  steps: ["Recency", "Frequency", "Monetary", "Score & tier", "Act per tier"],
  when: "Lifecycle & retention.",
  tool: {
    type: "calculator",
    title: "RFM Score Calculator",
    description: "Enter recency (days since last purchase), frequency (purchases in period), and monetary (total spend). Get the RFM score and segment.",
    inputs: [
      { id: "recency", label: "Recency (days since last purchase)", type: "number", default: 30 },
      { id: "frequency", label: "Frequency (purchases in 12 months)", type: "number", default: 4 },
      { id: "monetary", label: "Monetary value (total spend $)", type: "number", default: 500 },
    ],
    compute: (i) => {
      const r = Number(i.recency || 0);
      const f = Number(i.frequency || 0);
      const m = Number(i.monetary || 0);
      const rScore = r <= 30 ? 5 : r <= 60 ? 4 : r <= 120 ? 3 : r <= 365 ? 2 : 1;
      const fScore = f >= 10 ? 5 : f >= 5 ? 4 : f >= 3 ? 3 : f >= 1 ? 2 : 1;
      const mScore = m >= 1000 ? 5 : m >= 500 ? 4 : m >= 200 ? 3 : m >= 50 ? 2 : 1;
      const total = rScore + fScore + mScore;
      let segment = "At Risk";
      let color = "#f59e0b";
      if (total >= 13) { segment = "Champions"; color = "#16a34a"; }
      else if (total >= 10) { segment = "Loyal"; color = "#0ea5e9"; }
      else if (total >= 7) { segment = "Potential Loyalist"; color = "#7c3aed"; }
      else if (total >= 4) { segment = "At Risk"; color = "#f59e0b"; }
      else { segment = "Lost"; color = "#ef4444"; }
      return {
        verdict: `RFM: ${rScore}${fScore}${mScore} — ${segment}`,
        color,
        table: [
          { label: "Recency score", value: `${rScore}/5 (${r} days)`, tag: rScore >= 4 ? "Good" : "Low", tagColor: rScore >= 4 ? "#16a34a" : "#ef4444" },
          { label: "Frequency score", value: `${fScore}/5 (${f} purchases)`, tag: fScore >= 4 ? "Good" : "Low", tagColor: fScore >= 4 ? "#16a34a" : "#ef4444" },
          { label: "Monetary score", value: `${mScore}/5 ($${m})`, tag: mScore >= 4 ? "Good" : "Low", tagColor: mScore >= 4 ? "#16a34a" : "#ef4444" },
        ],
      };
    },
  },
},

