{
  id: "marketing_mix_7p",
  label: "7Ps Marketing Mix",
  author: "Booms & Bitner",
  category: "Customer",
  oneLine: "Product, price, place, promotion, people, process, physical evidence.",
  steps: ["Product", "Price", "Place", "Promotion", "People", "Process", "Physical evidence"],
  when: "Service marketing, full mix audits.",
  tool: {
    type: "scorecard",
    title: "7Ps Marketing Mix Audit",
    description: "Score each P. The weakest P drags the whole mix down.",
    inputs: [
      { id: "product", label: "Product — does it solve the right problem well?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "price", label: "Price — is it aligned with perceived value?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "place", label: "Place — can customers easily find & buy it?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "promotion", label: "Promotion — is your messaging reaching the right people?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "people", label: "People — does your team deliver the experience?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "process", label: "Process — is the customer journey smooth?", type: "slider", min: 0, max: 10, default: 5 },
      { id: "evidence", label: "Physical Evidence — do touchpoints reinforce the brand?", type: "slider", min: 0, max: 10, default: 5 },
    ],
    scoring: [
      { max: 40, label: "Unbalanced mix — fix the weakest P", color: "#ef4444" },
      { max: 60, label: "Developing — align the weak spots", color: "#f59e0b" },
      { max: 80, label: "Solid mix — optimize incrementally", color: "#0ea5e9" },
      { max: 100, label: "Excellent — all Ps aligned", color: "#16a34a" },
    ],
    compute: (i) => {
      const keys = ["product", "price", "place", "promotion", "people", "process", "evidence"];
      const vals = keys.map((k) => Number(i[k] || 0));
      const sum = vals.reduce((a, b) => a + b, 0);
      const min = Math.min(...vals);
      const weakest = keys[vals.indexOf(min)];
      const score = Math.round((sum / (keys.length * 10)) * 100);
      return { score, maxScore: 100, verdict: `Weakest P: ${weakest} (${min}/10)`, color: min >= 7 ? "#16a34a" : min >= 4 ? "#f59e0b" : "#ef4444" };
    },
  },
},

