{
  id: "nps",
  label: "Net Promoter Score",
  author: "Reichheld",
  category: "Customer",
  oneLine: "% promoters minus % detractors — one loyalty number.",
  steps: ["Ask the question", "Bucket responses", "Compute score", "Close the loop"],
  when: "Loyalty tracking.",
  tool: {
    type: "calculator",
    title: "NPS Calculator",
    description: "Enter your survey response counts. Promoters = 9-10, Passives = 7-8, Detractors = 0-6.",
    inputs: [
      { id: "promoters", label: "Promoters (9–10)", type: "number", default: 60 },
      { id: "passives", label: "Passives (7–8)", type: "number", default: 20 },
      { id: "detractors", label: "Detractors (0–6)", type: "number", default: 20 },
    ],
    compute: (i) => {
      const p = Number(i.promoters || 0);
      const pa = Number(i.passives || 0);
      const d = Number(i.detractors || 0);
      const total = p + pa + d;
      if (total === 0) return { verdict: "No responses", color: "#94a3b8" };
      const nps = Math.round(((p - d) / total) * 100);
      let label = "Good";
      let color = "#0ea5e9";
      if (nps >= 50) { label = "Excellent"; color = "#16a34a"; }
      else if (nps >= 0) { label = "Good"; color = "#0ea5e9"; }
      else if (nps >= -20) { label = "Needs work"; color = "#f59e0b"; }
      else { label = "Critical"; color = "#ef4444"; }
      return {
        verdict: `NPS: ${nps} — ${label}`,
        color,
        table: [
          { label: "Promoters", value: `${p} (${Math.round((p / total) * 100)}%)`, tag: "9–10", tagColor: "#16a34a" },
          { label: "Passives", value: `${pa} (${Math.round((pa / total) * 100)}%)`, tag: "7–8", tagColor: "#94a3b8" },
          { label: "Detractors", value: `${d} (${Math.round((d / total) * 100)}%)`, tag: "0–6", tagColor: "#ef4444" },
          { label: "Total responses", value: String(total), tag: "", tagColor: "" },
        ],
      };
    },
  },
},

