      { max: 80, label: "Balanced — optimize all four", color: "#0ea5e9" },
      { max: 100, label: "Excellent — well-rounded performance", color: "#16a34a" },
    ],
    compute: (i) => {
      const keys = ["financial", "customer", "internal", "learning"];
      const vals = keys.map((k) => Number(i[k] || 0));
      const sum = vals.reduce((a, b) => a + b, 0);
      const max = Math.max(...vals);
      const min = Math.min(...vals);
      const balance = max - min;
      const score = Math.round((sum / (keys.length * 10)) * 100);
      const verdict = balance > 4 ? `Imbalanced — spread of ${balance} between best & worst` : `Balanced — spread of ${balance}`;
      return { score, maxScore: 100, verdict, color: balance <= 2 && min >= 6 ? "#16a34a" : balance <= 3 ? "#0ea5e9" : "#f59e0b" };
    },
  },
},

