{
  id: "viral_loops",
  label: "Viral Loop / K-Factor",
  author: "Skok",
  category: "Growth",
  oneLine: "Each user brings >1 more — K > 1 means exponential growth.",
  steps: ["Build the loop", "Maximize invitations", "Minimize friction", "Track K-factor"],
  when: "PLG and network products.",
  tool: {
    type: "calculator",
    title: "Viral Coefficient (K-Factor) Calculator",
    description: "K = invitations per user × conversion rate. K > 1 means exponential organic growth.",
    inputs: [
      { id: "invites", label: "Invitations sent per user", type: "number", default: 5 },
      { id: "conversion", label: "Conversion rate of invitations (%)", type: "number", default: 20 },
    ],
    compute: (i) => {
      const invites = Number(i.invites || 0);
      const conv = Number(i.conversion || 0) / 100;
      const k = invites * conv;
      let label = "No organic growth — needs paid acquisition";
      let color = "#ef4444";
      if (k >= 1) { label = "Exponential growth — K > 1, the loop is self-sustaining"; color = "#16a34a"; }
      else if (k >= 0.5) { label = "Strong viral effect — reduce friction to push K > 1"; color = "#0ea5e9"; }
      else if (k >= 0.1) { label = "Weak viral effect — improve invitations or conversion"; color = "#f59e0b"; }
      return {
        verdict: `K = ${k.toFixed(2)} — ${label}`,
        color,
        table: [
          { label: "Invitations per user", value: String(invites), tag: invites >= 5 ? "Good" : "Low", tagColor: invites >= 5 ? "#16a34a" : "#f59e0b" },
          { label: "Invitation conversion", value: `${Number(i.conversion || 0)}%`, tag: conv >= 0.2 ? "Good" : "Low", tagColor: conv >= 0.2 ? "#16a34a" : "#f59e0b" },
          { label: "K-Factor", value: k.toFixed(2), tag: k >= 1 ? "Viral" : "Sub-viral", tagColor: k >= 1 ? "#16a34a" : "#ef4444" },
        ],
      };
    },
  },
},

