input.content:
"use client";
import { useMemo, useState } from "react";
import type { StrategyTool, ToolResult } from "@/lib/frameworks";
import { Check } from "lucide-react";

export function ScorecardTool({ tool }: { tool: StrategyTool }) {
  const defaults: Record<string, string | number> = {};
  for (const inp of tool.inputs) {
    defaults[inp.id] = inp.default ?? (inp.type === "slider" ? inp.min ?? 0 : "");
  }
  const [values, setValues] = useState<Record<string, string | number>>(defaults);
  const [computed, setComputed] = useState(false);

  const result: ToolResult | null = useMemo(() => {
    if (!computed) return null;
    return tool.compute(values);
  }, [computed, values, tool]);

  function setVal(id: string, v: string | number) {
    setValues((prev) => ({ ...prev, [id]: v }));
    setComputed(false);
  }

  const score = result?.score ?? 0;
  const maxScore = result?.maxScore ?? 100;
  const pct = Math.round((score / maxScore) * 100);
  const scoringBand = tool.scoring?.find((s) => pct <= s.max);
  const verdictColor = scoringBand?.color || result?.color || "#0ea5e9";

  return (
    <div className="space-y-4">
      <div className="space-y-3">
        {tool.inputs.map((inp) => {
          const val = Number(values[inp.id] || 0);
          return (
            <div key={inp.id}>
              <div className="flex items-center justify-between mb-1">
                <label className="text-sm font-medium">{inp.label}</label>
                <span
                  className="text-sm font-bold tabular-nums px-2 py-0.5 rounded"
                  style={{ background: `${verdictColor}18`, color: verdictColor }}
                >
                  {val}/{inp.max ?? 10}
                </span>
              </div>
              <input
                type="range"
                min={inp.min ?? 0}
                max={inp.max ?? 10}
                step={inp.step ?? 1}
                value={val}
                onChange={(e) => setVal(inp.id, Number(e.target.value))}
                className="w-full accent-[var(--accent)] cursor-pointer"
                style={{ accentColor: verdictColor }}
              />
            </div>
          );
        })}
      </div>

      <button
        className="btn btn-primary w-full"
        onClick={() => setComputed(true)}
      >
        <Check className="w-4 h-4" /> Score my strategy
      </button>

      {result && (
        <div className="space-y-3 pt-3 border-t" style={{ borderColor: "rgb(var(--border))" }}>
          <div className="flex items-center gap-4">
            <ScoreGauge pct={pct} color={verdictColor} />
            <div className="flex-1">
              {scoringBand && (
                <div className="text-sm font-bold" style={{ color: verdictColor }}>
                  {scoringBand.label}
                </div>
              )}
              {result.verdict && (
                <div className="text-xs muted mt-0.5">{result.verdict}</div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function ScoreGauge({ pct, color }: { pct: number; color: string }) {
  const radius = 34;
  const circ = 2 * Math.PI * radius;
  const offset = circ - (pct / 100) * circ;
  return (
    <div className="relative w-[80px] h-[80px] flex-shrink-0">
      <svg className="w-full h-full -rotate-90" viewBox="0 0 80 80">
        <circle
          cx="40"
          cy="40"
          r={radius}
          fill="none"
          strokeWidth="8"
          stroke="rgb(var(--hover))"
        />
        <circle
          cx="40"
          cy="40"
          r={radius}
          fill="none"
          strokeWidth="8"
          stroke={color}
          strokeDasharray={circ}
          strokeDashoffset={offset}
          strokeLinecap="round"
          style={{ transition: "stroke-dashoffset 0.5s ease" }}
        />
      </svg>
      <div className="absolute inset-0 grid place-items-center">
        <span className="text-xl font-bold tabular-nums">{pct}</span>
      </div>
    </div>
  );
}

