"use client";
import { useMemo, useState } from "react";
import type { StrategyTool, ToolResult } from "@/lib/frameworks";
import { Copy, Check, Sparkles } from "lucide-react";

export function TemplateTool({ tool }: { tool: StrategyTool }) {
  const defaults: Record<string, string | number> = {};
  for (const inp of tool.inputs) {
    defaults[inp.id] = inp.default ?? "";
  }
  const [values, setValues] = useState<Record<string, string | number>>(defaults);
  const [copied, setCopied] = useState(false);

  const result: ToolResult = useMemo(() => tool.compute(values), [values, tool]);

  function setVal(id: string, v: string) {
    setValues((prev) => ({ ...prev, [id]: v }));
  }

  async function copyOutput() {
    if (!result.output) return;
    try {
      await navigator.clipboard.writeText(result.output);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // ignore
    }
  }

  return (
    <div className="space-y-4">
      <div className="space-y-3">
        {tool.inputs.map((inp) => (
          <div key={inp.id}>
            <label className="text-sm font-medium block mb-1">{inp.label}</label>
            {inp.type === "text" && (
              <textarea
                className="input min-h-[60px] resize-y"
                value={String(values[inp.id] || "")}
                onChange={(e) => setVal(inp.id, e.target.value)}
                placeholder={inp.placeholder}
              />
            )}
          </div>
        ))}
      </div>

      {result.output && (
        <div className="space-y-2 pt-3 border-t" style={{ borderColor: "rgb(var(--border))" }}>
          <div className="flex items-center justify-between">
            <div className="text-xs uppercase tracking-wider muted flex items-center gap-1">
              <Sparkles className="w-3 h-3" /> Generated output
            </div>
            <button
              onClick={copyOutput}
              className="btn btn-ghost text-xs"
            >
              {copied ? <Check className="w-3 h-3 text-emerald-500" /> : <Copy className="w-3 h-3" />}
              {copied ? "Copied" : "Copy"}
            </button>
          </div>
          <div className="card p-4 bg-slate-50 dark:bg-zinc-800/50 whitespace-pre-wrap text-sm">
            {result.output}
          </div>
        </div>
      )}
    </div>
  );
}

