+  const defaults: Record<string, string | number> = {};
+  for (const inp of tool.inputs) {
+    defaults[inp.id] = inp.default ?? (inp.type === "number" ? 0 : "");
+  }
+  const [values, setValues] = useState<Record<string, string | number>>(defaults);
+
+  const result: ToolResult = useMemo(() => tool.compute(values), [values, tool]);
+
+  function setVal(id: string, v: string | number) {
+    setValues((prev) => ({ ...prev, [id]: v }));
+  }
+
+  const verdictColor = result.color || "#0ea5e9";
+
+  return (
+    <div className="space-y-4">
+      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
+        {tool.inputs.map((inp) => (
+          <div key={inp.id} className={inp.type === "text" ? "sm:col-span-2" : ""}>
+            <label className="text-sm font-medium block mb-1">{inp.label}</label>
+            {inp.type === "number" && (
+              <input
+                type="number"
+                className="input"
+                value={Number(values[inp.id] || 0)}
+                onChange={(e) => setVal(inp.id, Number(e.target.value))}
+                step={inp.step ?? "any"}
+              />
+            )}
+            {inp.type === "text" && (
+              <input
+                type="text"
+                className="input"
+                value={String(values[inp.id] || "")}
+                onChange={(e) => setVal(inp.id, e.target.value)}
+                placeholder={inp.placeholder}
+              />
+            )}
+          </div>
+        ))}
+      </div>
+
+      <div className="space-y-3 pt-3 border-t" style={{ borderColor: "rgb(var(--border))" }}>
+        {result.verdict && (
+          <div
+            className="card p-4 text-center"
+            style={{ background: `${verdictColor}10`, borderColor: `${verdictColor}40` }}
+          >
+            <Calculator className="w-5 h-5 mx-auto mb-2" style={{ color: verdictColor }} />
+            <div className="font-bold text-lg" style={{ color: verdictColor }}>
+              {result.verdict}
+            </div>
+          </div>
+        )}
+
+        {result.table && result.table.length > 0 && (
+          <div className="card overflow-hidden">
+            <table className="w-full text-sm">
+              <tbody>
+                {result.table.map((row, i) => (
+                  <tr
+                    key={i}
+                    className="border-b last:border-b-0"
+                    style={{ borderColor: "rgb(var(--border))" }}
+                  >
+                    <td className="px-3 py-2 font-medium">{row.label}</td>
+                    <td className="px-3 py-2 text-right tabular-nums">{row.value}</td>
+                    {row.tag && (
+                      <td className="px-3 py-2 text-right">
+                        <span
+                          className="text-[10px] font-bold uppercase px-1.5 py-0.5 rounded"
+                          style={{
+                            background: `${row.tagColor || "#94a3b8"}18`,
+                            color: row.tagColor || "#94a3b8",
+                          }}
+                        >
+                          {row.tag}
+                        </span>
+                      </td>
+                    )}
+                  </tr>
+                ))}
+              </tbody>
+            </table>
+          </div>
+        )}
+      </div>
+    </div>
+  );
