input.content:
"use client";
import { useMemo, useState } from "react";
import type { StrategyTool, ToolResult } from "@/lib/frameworks";
import { ChevronRight, RotateCcw, Check } from "lucide-react";
import clsx from "clsx";

export function DecisionTreeTool({ tool }: { tool: StrategyTool }) {
  const defaults: Record<string, string | number> = {};
  for (const inp of tool.inputs) {
    defaults[inp.id] = inp.default ?? "";
  }
  const [values, setValues] = useState<Record<string, string | number>>(defaults);

  const allAnswered = tool.inputs.every((inp) => values[inp.id] !== "" && values[inp.id] !== undefined);
  const result: ToolResult | null = useMemo(() => {
    if (!allAnswered) return null;
    return tool.compute(values);
  }, [allAnswered, values, tool]);

  function setVal(id: string, v: string) {
    setValues((prev) => ({ ...prev, [id]: v }));
  }

  function reset() {
    const cleared: Record<string, string | number> = {};
    for (const inp of tool.inputs) cleared[inp.id] = "";
    setValues(cleared);
  }

  const verdictColor = result?.color || "#0ea5e9";

  return (
    <div className="space-y-4">
      <div className="space-y-4">
        {tool.inputs.map((inp, idx) => {
          const isRadio = inp.type === "radio";
          const isSelect = inp.type === "select";
          const currentVal = String(values[inp.id] || "");
          const answered = currentVal !== "";

          return (
            <div
              key={inp.id}
              className={clsx(
                "rounded-lg p-3 border transition-all",
                answered
                  ? "border-[rgb(var(--border))] bg-[rgb(var(--hover))]"
                  : "border-[var(--accent)] bg-[rgba(var(--theme-brand-rgb),0.03)]",
              )}
            >
              <div className="flex items-start gap-2">
                <span
                  className={clsx(
                    "w-5 h-5 rounded-full grid place-items-center text-[10px] font-bold flex-shrink-0 mt-0.5",
                    answered
                      ? "bg-emerald-500 text-white"
                      : "bg-[var(--accent)] text-white",
                  )}
                >
                  {answered ? <Check className="w-3 h-3" /> : idx + 1}
                </span>
                <div className="flex-1">
                  <label className="text-sm font-medium block mb-2">{inp.label}</label>
                  {(isRadio || isSelect) && inp.options && (
                    <div className="flex flex-wrap gap-2">
                      {inp.options.map((opt) => (
                        <button
                          key={opt}
                          onClick={() => setVal(inp.id, opt)}
                          className={clsx(
                            "px-3 py-1.5 rounded-lg text-sm border transition-all text-left",
                            currentVal === opt
                              ? "border-[var(--accent)] text-[var(--accent)] bg-[rgba(var(--theme-brand-rgb),0.06)] font-semibold"
                              : "border-[rgb(var(--border))] muted hover:bg-[rgb(var(--hover))]",
                          )}
                        >
                          {opt}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {allAnswered && result && (
        <div
          className="card p-4 space-y-2"
          style={{ background: `${verdictColor}08`, borderColor: `${verdictColor}40` }}
        >
          <div className="flex items-center gap-2">
            <ChevronRight className="w-5 h-5" style={{ color: verdictColor }} />
            <span className="text-xs uppercase tracking-wider muted">Recommendation</span>
          </div>
          <div className="font-bold text-base" style={{ color: verdictColor }}>
            {result.verdict}
          </div>
          {result.score !== undefined && (
            <div className="text-xs muted">Confidence: {result.score}/{result.maxScore ?? 100}</div>
          )}
        </div>
      )}

      {allAnswered && (
        <button onClick={reset} className="btn btn-ghost text-xs w-full">
          <RotateCcw className="w-3 h-3" /> Start over
        </button>
      )}
    </div>
  );
}

