"use client";
import { useMemo, useState } from "react";
import Link from "next/link";
import {
  Sparkles,
  Search,
  ChevronRight,
  ChevronDown,
  Play,
  Target,
  Filter,
  Users,
  TrendingUp,
  Palette,
  Radio,
  Globe,
  BarChart3,
  BookOpen,
  ArrowRight,
} from "lucide-react";
import {
  STRATEGY_FRAMEWORKS,
  STRATEGY_CATEGORIES,
  type StrategyFramework,
  type ToolType,
} from "@/lib/frameworks";
import { ScorecardTool } from "@/components/strategy/ScorecardTool";
import { TemplateTool } from "@/components/strategy/TemplateTool";
import { CalculatorTool } from "@/components/strategy/CalculatorTool";
import { DecisionTreeTool } from "@/components/strategy/DecisionTreeTool";
import clsx from "clsx";

const CAT_META: Record<
  string,
  { icon: React.ComponentType<{ className?: string }>; color: string }
> = {
  Positioning: { icon: Target, color: "#7c3aed" },
  Competitive: { icon: Filter, color: "#dc2626" },
  Growth: { icon: TrendingUp, color: "#16a34a" },
  Brand: { icon: Palette, color: "#db2777" },
  Customer: { icon: Users, color: "#0ea5e9" },
  Channel: { icon: Globe, color: "#f59e0b" },
  Analysis: { icon: BarChart3, color: "#64748b" },
};

const TOOL_LABELS: Record<ToolType, string> = {
  scorecard: "Scorecard",
  template: "Worksheet",
  calculator: "Calculator",
  decision_tree: "Decision Tree",
};

const TOOL_COLORS: Record<ToolType, string> = {
  scorecard: "#16a34a",
  template: "#7c3aed",
  calculator: "#0ea5e9",
  decision_tree: "#f59e0b",
};

export default function FrameworksPage() {
  const [cat, setCat] = useState<string>("All");
  const [query, setQuery] = useState("");
  const [toolFilter, setToolFilter] = useState<string>("All");
  const [openId, setOpenId] = useState<string | null>(null);
  const [executingId, setExecutingId] = useState<string | null>(null);

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    return STRATEGY_FRAMEWORKS.filter((f) => {
      if (cat !== "All" && f.category !== cat) return false;
      if (toolFilter === "With tools" && !f.tool) return false;
      if (toolFilter === "Reference only" && f.tool) return false;
      if (!q) return true;
      return (
        f.label.toLowerCase().includes(q) ||
        f.author.toLowerCase().includes(q) ||
        f.oneLine.toLowerCase().includes(q) ||
        f.id.toLowerCase().includes(q)
      );
    });
  }, [cat, query, toolFilter]);

  const tabs = ["All", ...STRATEGY_CATEGORIES];
  const toolCount = STRATEGY_FRAMEWORKS.filter((f) => f.tool).length;

  return (
    <div className="space-y-5">
      {/* Header */}
      <header className="flex items-start justify-between gap-4 flex-wrap">
        <div>
          <div className="flex items-center gap-2">
            <span className="text-xs font-bold uppercase tracking-wider muted">Strategy</span>
            <span className="text-xs muted">/</span>
            <span className="text-xs font-bold uppercase tracking-wider text-[var(--accent)]">
              Frameworks
            </span>
          </div>
          <h1 className="text-xl font-bold mt-1">Strategy Framework Library</h1>
          <p className="text-sm muted mt-1 max-w-2xl">
            {STRATEGY_FRAMEWORKS.length} frameworks across {STRATEGY_CATEGORIES.length} categories.
            {toolCount} come with execution tools — scorecards, worksheets, calculators, and
            decision trees you can run right now.
          </p>
        </div>
        <Link href="/strategy/stp" className="btn btn-ghost text-sm">
          <ArrowRight className="w-4 h-4 rotate-180" /> STP Protocol
        </Link>
      </header>

      {/* Search */}
      <div className="flex items-center gap-2 flex-wrap">
        <div className="relative flex-1 min-w-[200px]">
          <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 muted" />
          <input
            className="input pl-10"
            placeholder="Search frameworks by name, author, or concept…"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
          />
        </div>
        <div className="flex gap-1.5">
          {["All", "With tools", "Reference only"].map((t) => (
            <button
              key={t}
              onClick={() => setToolFilter(t)}
              className={clsx(
                "px-2.5 py-1.5 rounded-lg text-xs font-semibold border transition-colors",
                toolFilter === t
                  ? "border-[var(--accent)] text-[var(--accent)] bg-[rgba(var(--theme-brand-rgb),0.06)]"
                  : "border-[rgb(var(--border))] muted hover:bg-[rgb(var(--hover))]",
              )}
            >
              {t}
            </button>
          ))}
        </div>
      </div>

      {/* Category tabs */}
      <div className="flex flex-wrap gap-1.5">
        {tabs.map((t) => {
          const meta = CAT_META[t];
          const Icon = meta?.icon || BookOpen;
          return (
            <button
              key={t}
              onClick={() => setCat(t)}
              className={clsx(
                "flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold border transition-colors",
                cat === t
                  ? "border-[var(--accent)] text-[var(--accent)] bg-[rgba(var(--theme-brand-rgb),0.06)]"
                  : "border-[rgb(var(--border))] muted hover:bg-[rgb(var(--hover))]",
              )}
            >
              <Icon className="w-3.5 h-3.5" />
              {t}
            </button>
          );
        })}
      </div>

