                      <Sparkles
                        className="w-4 h-4"
                        style={{ color: TOOL_COLORS[f.tool.type] }}
                      />
                      {f.tool.title}
                    </div>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        onExecute();
                      }}
                      className="text-xs muted hover:text-[var(--accent)]"
                    >
                      Collapse
                    </button>
                  </div>
                  <p className="text-xs muted">{f.tool.description}</p>
                  <div className="card p-4 bg-slate-50/50 dark:bg-zinc-800/30">
                    {f.tool.type === "scorecard" && <ScorecardTool tool={f.tool} />}
                    {f.tool.type === "template" && <TemplateTool tool={f.tool} />}
                    {f.tool.type === "calculator" && <CalculatorTool tool={f.tool} />}
                    {f.tool.type === "decision_tree" && <DecisionTreeTool tool={f.tool} />}
                  </div>
                </div>
              )}
            </div>
          ) : (
            <div className="text-xs muted italic pt-2">
              Reference framework — no execution tool yet.
            </div>
          )}
        </div>
      )}
    </div>
  );
}

