/* ───────────────────────── Strategy Library ───────────────────────── */
function StrategyLibrary() {
  const [cat, setCat] = useState<(typeof STRATEGY_CATEGORIES)[number] | "All">("All");
  const [open, setOpen] = useState<string | null>("stp");
  const [query, setQuery] = useState("");

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    return STRATEGY_FRAMEWORKS.filter((f) => {
      if (cat !== "All" && f.category !== cat) return false;
      if (!q) return true;
      return (
        f.label.toLowerCase().includes(q) ||
        f.author.toLowerCase().includes(q) ||
        f.oneLine.toLowerCase().includes(q) ||
        f.id.toLowerCase().includes(q)
      );
    });
  }, [cat, query]);

  const tabs: ("All" | (typeof STRATEGY_CATEGORIES)[number])[] = ["All", ...STRATEGY_CATEGORIES];

  return (
    <section className="space-y-3">
      <div className="flex items-start justify-between gap-3 flex-wrap">
        <div>
          <div className="flex items-center gap-2">
            <Sparkles className="w-4 h-4 text-[var(--accent)]" />
            <h2 className="font-bold">Strategy Library</h2>
            <span className="chip bg-[rgb(var(--hover))] text-[rgb(var(--text-secondary))] text-[10px] font-bold uppercase">
              {STRATEGY_FRAMEWORKS.length} frameworks
            </span>
          </div>
          <p className="text-sm muted mt-1 max-w-2xl">
            The complete playbook shelf. Each framework tells you which decision it answers, the
            steps, and when to reach for it. The STP protocol is at the top — the rest extend it.
          </p>
        </div>
        <input
          className="input max-w-[240px]"
          placeholder="Search frameworks…"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
        />
      </div>

      <div className="flex flex-wrap gap-1.5">
        {tabs.map((t) => (
          <button
            key={t}
            onClick={() => setCat(t)}
            className={clsx(
              "px-2.5 py-1 rounded-full text-xs font-semibold transition-colors border",
              cat === t
                ? "border-[var(--accent)] text-[var(--accent)] bg-[rgba(var(--theme-brand-rgb),0.06)]"
                : "border-[rgb(var(--border))] muted hover:bg-[rgb(var(--hover))]",
            )}
          >
            {t}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
        {filtered.map((f) => (
          <FrameworkCard
            key={f.id}
            f={f}
            open={open === f.id}
            onToggle={() => setOpen(open === f.id ? null : f.id)}
          />
        ))}
      </div>
      {filtered.length === 0 && (
        <div className="card card-pad text-center py-10 text-sm muted">
          No frameworks match “{query}”.
        </div>
      )}
    </section>
  );
}

function FrameworkCard({
  f,
  open,
  onToggle,
}: {
  f: StrategyFramework;
  open: boolean;
  onToggle: () => void;
}) {
  const catColor: Record<string, string> = {
    Positioning: "#7c3aed",
    Competitive: "#dc2626",
    Growth: "#16a34a",
    Brand: "#db2777",
    Customer: "#0ea5e9",
    Channel: "#f59e0b",
    Analysis: "#64748b",
  };
  const color = catColor[f.category] || "var(--accent)";
  return (
    <button
      onClick={onToggle}
      className="card card-pad text-left transition-all hover:shadow-md w-full"
    >
      <div className="flex items-start justify-between gap-2">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-1">
            <span
              className="text-[10px] font-bold uppercase tracking-wider px-1.5 py-0.5 rounded"
              style={{ background: `${color}18`, color }}
            >
              {f.category}
            </span>
            {f.id === "stp" && (
              <span className="text-[10px] font-bold uppercase tracking-wider text-[var(--accent)]">
                ● Active
              </span>
            )}
          </div>
          <div className="font-semibold">{f.label}</div>
          <div className="text-xs muted">{f.author}</div>
        </div>
        {open ? (
          <ArrowLeft className="w-4 h-4 muted rotate-90 flex-shrink-0" />
        ) : (
          <ArrowRight className="w-4 h-4 muted rotate-90 flex-shrink-0" />
        )}
      </div>

      <p className="text-sm mt-2">{f.oneLine}</p>

      {open && (
        <div className="mt-3 pt-3 border-t space-y-2" style={{ borderColor: "rgb(var(--border))" }}>
          <div>
            <div className="text-[10px] uppercase tracking-wider muted mb-1">Steps</div>
            <ol className="text-xs space-y-1">
              {f.steps.map((s, i) => (
                <li key={i} className="flex items-start gap-1.5">
                  <span
                    className="w-4 h-4 rounded-full grid place-items-center text-[9px] font-bold flex-shrink-0 mt-0.5"
                    style={{ background: `${color}22`, color }}
                  >
                    {i + 1}
                  </span>
                  <span>{s}</span>
                </li>
              ))}
            </ol>
          </div>
          <div>
            <div className="text-[10px] uppercase tracking-wider muted mb-0.5">When to use</div>
            <div className="text-xs">{f.when}</div>
          </div>
          {f.pairsWith && f.pairsWith.length > 0 && (
            <div>
              <div className="text-[10px] uppercase tracking-wider muted mb-0.5">Pairs with</div>
              <div className="flex flex-wrap gap-1">
                {f.pairsWith.map((p) => {
                  const match = STRATEGY_FRAMEWORKS.find((x) => x.id === p);
                  return (
                    <span key={p} className="chip bg-[rgb(var(--hover))] text-[rgb(var(--text-secondary))] text-[10px]">
                      {match?.label || p}
                    </span>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      )}
    </button>
  );
}

